<!-- wp:proposal-crafter/paragraph {"uniqueId":"751283f","css":".pc751283f{border-style:none;border-color:#000000;border-width:0px 0px 0px 0px;margin:0px 0px 60px 0px !important;}.pc751283f__overlay{padding:0px 0px 0px 0px !important;}.pc751283f .pc-paragraph{text-align:left;color:#707070;font-size:12px;font-family:DM Sans;font-weight:400;}","content":"\u003cbr\u003eDue to the lengthy and often costly procedures required to initiate any form of trademark, copyright and legal name search, I am unable to provide any practical help with this.\u003cbr\u003e\u003cbr\u003eIf you require the logo to be registered as a trademark, kindly seek proper legal advice.","fontSize":12,"fontFamily":"DM Sans","color":"#707070","margin":{"top":"0px","right":"0px","bottom":"60px","left":"0px"}} -->
<div class="wp-block-proposal-crafter-paragraph pc751283f" data-block-id="751283f"><div class="pc751283f__overlay"><p class="pc-paragraph"><br>Due to the lengthy and often costly procedures required to initiate any form of trademark, copyright and legal name search, I am unable to provide any practical help with this.<br><br>If you require the logo to be registered as a trademark, kindly seek proper legal advice.</p></div></div>
